 1	import { ResourceLink, useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 2	import {
 3	  FormGroup,
 4	  FormHelperText,
 5	  FormSelect,
 6	  FormSelectOption,
 7	  HelperText,
 8	  HelperTextItem,
 9	} from '@patternfly/react-core';
10	import * as React from 'react';
11	import { ClusterIssuer } from './types'; // You will need to define this type similarly to Gateway.
12	import { useTranslation } from 'react-i18next';
13	
14	interface ClusterIssuerSelectProps {
15	  selectedClusterIssuer: ClusterIssuer;
16	  onChange: (updated: ClusterIssuer) => void;
17	}
18	
19	const ClusterIssuerSelect: React.FC<ClusterIssuerSelectProps> = ({
20	  selectedClusterIssuer,
21	  onChange,
22	}) => {
23	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
24	  const [clusterIssuers, setClusterIssuers] = React.useState([]);
25	  const gvk = { group: 'cert-manager.io', version: 'v1', kind: 'ClusterIssuer' };
26	
27	  const clusterIssuerResource = {
28	    groupVersionKind: gvk,
29	    isList: true,
30	  };
31	
32	  const [clusterIssuerData, clusterIssuerLoaded, clusterIssuerError] =
33	    useK8sWatchResource(clusterIssuerResource);
34	
35	  React.useEffect(() => {
36	    if (clusterIssuerLoaded && !clusterIssuerError && Array.isArray(clusterIssuerData)) {
37	      setClusterIssuers(
38	        clusterIssuerData.map((clusterIssuer) => ({
39	          name: clusterIssuer.metadata.name,
40	        })),
41	      );
42	    }
43	  }, [clusterIssuerData, clusterIssuerLoaded, clusterIssuerError]);
44	
45	  const handleClusterIssuerChange = (event: React.FormEvent<HTMLSelectElement>) => {
46	    const [name] = event.currentTarget.value.split('/');
47	    onChange({ ...selectedClusterIssuer, name });
48	  };
49	
50	  return (
51	    <>
52	      <FormGroup
53	        label={t('ClusterIssuer API Target Reference')}
54	        isRequired
55	        fieldId="clusterissuer-select"
56	      >
57	        <FormSelect
58	          id="clusterissuer-select"
59	          value={`${selectedClusterIssuer.name}`}
60	          onChange={handleClusterIssuerChange}
61	          aria-label={t('Select ClusterIssuer')}
62	        >
63	          <FormSelectOption
64	            key="placeholder"
65	            value=""
66	            label={t('Select an ClusterIssuer')}
67	            isPlaceholder
68	          />
69	          {clusterIssuers.map((clusterIssuer, index) => (
70	            <FormSelectOption
71	              key={index}
72	              value={`${clusterIssuer.name}`}
73	              label={`${clusterIssuer.name}`}
74	            />
75	          ))}
76	        </FormSelect>
77	        <FormHelperText>
78	          <HelperText>
79	            <HelperTextItem>
80	              {t(
81	                'Cluster Issuer: Reference to the cluster issuer for the created certificate. To create an additional ClusterIssuer go to',
82	              )}{' '}
83	              <ResourceLink
84	                groupVersionKind={gvk}
85	                title="Create an ClusterIssuer"
86	                hideIcon={true}
87	                inline={true}
88	                displayName="here"
89	              />
90	            </HelperTextItem>
91	          </HelperText>
92	        </FormHelperText>
93	      </FormGroup>
94	    </>
95	  );
96	};
97	
98	export default ClusterIssuerSelect;

